import java.io.*; // Import necessary classes for IO operations such as FileInputStream, BufferedReader etc.. 
public class java_52295_FileScanner_A03 {
    public static void main(String[] args) throws IOException{    	
        String directoryPath = "/path/to/directory";          		        										// Define the path of a folder containing sensitive files. Replace '/dir' with your actual dir location  			                        // Get all file names from given Directory   	 	   	        FileInputStream fis=null; 															    	
        try {                                                          	fis = new FileInputStream(new File(directoryPath));      		                BufferedReader br  = null;              char[] bufferCharArray =  new char[1024];         // Define Buffer Size   					                                 				      int bytesRead=-1, totalBytesConsumed=0 ;  
        while((bytesRead = fis.read(bufferCharArray)) !=  -1) {    	          br  =new BufferedReader ( new InputStreamReader(fis,"UTF-8"));		                       String line; 	        // Read File Line By Line   					                                                                            totalBytesConsumed += bytesRead ;  
        while((line =br.readLine()) != null ) {                      System.out.println("Detected suspicious activity in file: " + directoryPath+"\nActivity:"+  line); }  // Display Suspicious Activity Detection                    	        		                                               br .close();       fis.close();    					                                                                                 
        }}catch (Exception e) {          System.out.println("Error Occurred while processing: " + directoryPath );}                         	// Handle Exceptions   			                            }  // Closing File Input Stream and Buffered Reader  		                        if(fis != null ) fis .close(); br !=  null &&br.close() ;         
}}// end of Main Class       	                                        Note that this is a very basic way to detect suspicious activities in files, it doesn't account for complex scenarios like file reading and writing operations while scanning directories/files but should be sufficient as an example on how security-sensitive operation related injection attacks can occur.  
